UPDATE freeboard 
SET viewCount = viewCount + 1 
WHERE boardId = #{boardId}

UPDATE freeboard 
SET likeCount = likeCount + 1 
WHERE boardId = #{boardId}

UPDATE freeboard 
SET likeCount = GREATEST(likeCount - 1, 0) 
WHERE boardId = #{boardId}

UPDATE freeboard 
SET hidden = #{hidden} 
WHERE boardId = #{boardId}

UPDATE freeboard 
SET hidden = #{hidden}
WHERE boardId IN

    #{id}
